"""Spec loading and caching for API clients."""

import gzip
import json
import logging
from importlib import resources
from typing import Any, Dict, Optional

from .logging import configure_logger

logger = logging.getLogger("greennode_agentbase.core")
configure_logger(logger)

# Global cache for loaded specs
_spec_cache: Dict[str, Dict[str, Any]] = {}


def load_spec(service_name: str) -> Dict[str, Any]:
    """Load API specification for a service.

    Tries api.json.gz first (decompressed), then api.json (plain JSON) if not found.

    Args:
        service_name: Name of the service (e.g., "identity")

    Returns:
        Parsed API specification dictionary

    Raises:
        FileNotFoundError: If neither spec file can be found
        ValueError: If the spec file is invalid JSON
    """
    # Check cache first
    if service_name in _spec_cache:
        return _spec_cache[service_name]

    import os

    spec_dir = f"specs/{service_name}"
    current_dir = os.path.dirname(os.path.dirname(os.path.dirname(__file__)))
    fs_spec_dir = os.path.join(current_dir, "specs", service_name)

    # Try api.json.gz first (package resources, then filesystem)
    raw_data = None
    try:
        with resources.files("greennode_agentbase").joinpath(
            f"{spec_dir}/api.json.gz"
        ).open("rb") as f:
            raw_data = f.read()
    except (FileNotFoundError, ModuleNotFoundError, ValueError):
        gz_path = os.path.join(fs_spec_dir, "api.json.gz")
        if os.path.exists(gz_path):
            with open(gz_path, "rb") as f:
                raw_data = f.read()

    if raw_data is not None:
        try:
            decompressed_data = gzip.decompress(raw_data)
            spec = json.loads(decompressed_data.decode("utf-8"))
        except (gzip.BadGzipFile, json.JSONDecodeError) as e:
            raise ValueError(f"Invalid API specification format: {e}") from e
        _spec_cache[service_name] = spec
        logger.debug(f"Loaded API specification for service '{service_name}' (gzip)")
        return spec

    # Fallback to plain api.json
    try:
        with resources.files("greennode_agentbase").joinpath(
            f"{spec_dir}/api.json"
        ).open("r", encoding="utf-8") as f:
            spec = json.load(f)
    except (FileNotFoundError, ModuleNotFoundError, ValueError):
        json_path = os.path.join(fs_spec_dir, "api.json")
        if os.path.exists(json_path):
            with open(json_path, "r", encoding="utf-8") as f:
                spec = json.load(f)
        else:
            raise FileNotFoundError(
                f"API specification not found for service '{service_name}'. "
                f"Expected at: {fs_spec_dir}/api.json.gz or api.json"
            ) from None

    _spec_cache[service_name] = spec
    logger.debug(f"Loaded API specification for service '{service_name}' (json)")
    return spec


def clear_cache(service_name: Optional[str] = None) -> None:
    """Clear the spec cache.

    Args:
        service_name: Optional service name to clear. If None, clears all caches.
    """
    if service_name:
        _spec_cache.pop(service_name, None)
    else:
        _spec_cache.clear()

